package com.i2i.voltwise.sensors;
import com.fasterxml.jackson.databind.ObjectMapper;import org.springframework.beans.factory.annotation.Value;import org.springframework.kafka.annotation.KafkaListener;import org.springframework.kafka.core.KafkaTemplate;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Component;import java.time.Instant;import java.util.*;import java.util.concurrent.*;
@Component public class SensorEngine { record Device(UUID id,String name,double limit){} private final Map<UUID,List<Device>> homes=new ConcurrentHashMap<>();private final ObjectMapper json;private final KafkaTemplate<String,String> kafka;@Value("${voltwise.telemetry-topic}")String telemetryTopic;SensorEngine(ObjectMapper j,KafkaTemplate<String,String> k){json=j;kafka=k;} @KafkaListener(topics="${voltwise.registration-topic}") public void register(String payload){try{var root=json.readTree(payload);UUID home=UUID.fromString(root.get("homeId").asText());var devices=new ArrayList<Device>();root.withArray("appliances").forEach(a->devices.add(new Device(UUID.fromString(a.get("id").asText()),a.get("name").asText(),a.get("safeWattLimit").asDouble())));homes.put(home,devices);}catch(Exception ignored){}} @Scheduled(fixedDelayString="${voltwise.interval-ms}") public void emit(){var random=ThreadLocalRandom.current();homes.forEach((home,devices)->devices.forEach(d->{double multiplier=random.nextDouble()<.12?random.nextDouble(1.05,1.45):random.nextDouble(.25,.9);var event=Map.of("homeId",home,"applianceId",d.id(),"watts",Math.round(d.limit()*multiplier*10)/10d,"capturedAt",Instant.now().toString());try{kafka.send(telemetryTopic,home.toString(),json.writeValueAsString(event));}catch(Exception ignored){}}));} }
